import requests

BASE_URL = "http://localhost:8000"
LOGIN_URL = f"{BASE_URL}/api/auth/login"
ROLES_URL = f"{BASE_URL}/api/roles"
TIMEOUT = 30

def test_post_api_roles_create_role_with_permissions():
    # Step 1: Login to get access token
    login_payload = {
        "username": "zzzz",
        "password": "As123321",
        "company_code": "ae4e964a"
    }
    headers_login = {
        "Content-Type": "application/x-www-form-urlencoded"
    }
    try:
        login_resp = requests.post(LOGIN_URL, data=login_payload, headers=headers_login, timeout=TIMEOUT)
        assert login_resp.status_code == 200, f"Login failed with status {login_resp.status_code}: {login_resp.text}"
        login_json = login_resp.json()
        access_token = login_json.get("access_token")
        assert access_token, "No access_token found in login response"
    except Exception as e:
        raise AssertionError(f"Login request failed: {e}")

    # Step 2: Create a new role with permissions
    headers_role = {
        "Authorization": f"Bearer {access_token}",
        "Content-Type": "application/json"
    }
    role_payload = {
        "role_name": "test_role_permissions",
        "permissions": [
            "accounting.manage",
            "reports.view"
        ]
    }
    role_id = None
    try:
        resp = requests.post(ROLES_URL, json=role_payload, headers=headers_role, timeout=TIMEOUT)
        assert resp.status_code == 201, f"Role creation failed with status {resp.status_code}: {resp.text}"
        resp_json = resp.json()
        role_id = resp_json.get("id")
        assert role_id is not None, "Created role id missing in response"
    finally:
        # Cleanup: Delete the created role if possible
        if role_id:
            try:
                del_resp = requests.delete(f"{ROLES_URL}/{role_id}", headers=headers_role, timeout=TIMEOUT)
                # Accept 204 No Content or 200 OK or 404 Not Found if already deleted
                assert del_resp.status_code in (200, 204, 404), f"Role cleanup failed with status {del_resp.status_code}: {del_resp.text}"
            except Exception:
                # Log or ignore cleanup failure silently as test focus is creation
                pass

test_post_api_roles_create_role_with_permissions()

import requests

def test_get_root_serve_frontend_application_shell():
    url = "http://localhost:8000/"
    headers = {
        "Accept": "text/html"
    }
    try:
        response = requests.get(url, headers=headers, timeout=30)
        assert response.status_code == 200, f"Expected status code 200, got {response.status_code}"
        content_type = response.headers.get("Content-Type", "")
        assert "text/html" in content_type, f"Expected 'text/html' in Content-Type, got {content_type}"
        # Response content is expected HTML for SPA shell
        assert response.text.strip().startswith("<!DOCTYPE html>") or "<html" in response.text.lower(), "Response body does not appear to be HTML content."
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

test_get_root_serve_frontend_application_shell()
